var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크. 오. 오.","JPN":"グ、オ、オ、オ。","ENG":"KR. RR. RR.","TWN":"吼，吼，吼。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"성야의. 저주는. 이 정도로. 막을 수 없다.","JPN":"聖夜の、呪いは、この程度では、防げない。","ENG":"No one. Can. Stop... the Curse of the Holy Night!","TWN":"僅憑這點.是無法.阻擋.耶誕的詛咒。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"쓰러뜨려도 쓰러뜨려도 계속 일어나는군요.","JPN":"倒しても、倒しても、また立ち上がりますね。","ENG":"They just wouldn't stay down.","TWN":"不管怎麼攻擊，他們都能重新站起來。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"주인님을 다치게 할 수는 없으니...... 이래선 끝이 나지 않겠어요.","JPN":"ご主人様に怪我を負わせるわけにはいかないので……このままでは埒が明きません。","ENG":"I can't hurt my master. This is never going to end.","TWN":"總不能讓主人受傷……這樣下去是解決不了的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"진짜 좀비라도 됐다는 거야? 아무리 그래도 기계까지 변하는 건 뭔가 이상하잖아!","JPN":"本当にゾンビにでもなったってこと？　いくら何でも機械まで影響されるなんて、おかしすぎるよ！","ENG":"Have they really turned into zombies? But machines can't do that. This doesn't make sense at all.","TWN":"還真當自己是僵屍了？就算如此，連機器都變成這個樣子，未免也太奇怪了吧！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"베로니카 씨, 이대로 계속 버티기만 할 수는 없어요.","JPN":"ベロニカさん、このまま耐え続けるのは不可能です。","ENG":"Veronica, we can't last long doing this.","TWN":"貝洛妮卡，這麼死撐下去也不是辦法。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"좋은 방법이 있으신가요?","JPN":"何か良い方法があるのですか？","ENG":"Do you have any better idea?","TWN":"您有什麼好的辦法嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"팀을 나누죠. 내키지는 않지만.","JPN":"チームを分けましょう。気乗りはしませんが。","ENG":"I really don't want to do it, but let's split.","TWN":"雖然不想，但我們分幾個小隊吧。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"저와 실비아 씨가 선배를 추적할게요.","JPN":"私とシルビアさんが先輩を追跡します。","ENG":"Sylvia and I will go after Shiyoon.","TWN":"由我和希爾維亞追蹤前輩。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"베로니카 씨는 그동안 다른 분들과 희생자들을 막아 주세요.","JPN":"ベロニカさんはその間、他の人たちと犠牲者を守ってください。","ENG":"In the meantime, Veronica, I'd like you to stall the victims with the others.","TWN":"貝洛妮卡，妳和其他人一起阻止這些人進攻。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"두 분만으로는 고전하시던 걸로 기억합니다. 괜찮으시겠습니까?","JPN":"二人だけでは苦戦するかと思われますが、大丈夫ですか？","ENG":"If my memory serves me right, you two struggled against him. Are you sure about this?","TWN":"僅靠妳們兩個人恐怕會是一場苦戰，真的沒問題嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"어떻게든 해 봐야죠.","JPN":"何とかやってみます。","ENG":"We'll manage. Somehow.","TWN":"總得試一試。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"지금 이 현상의 원인으로 가장 의심스러운 사람은......","JPN":"この現象の原因として、最も怪しい人は……","ENG":"The most likely suspect of this phenomenon is...","TWN":"以現在這個情況，最可疑的人是……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"뭐, 아시잖아요.","JPN":"まあ、ご存知でしょう。","ENG":"Well, you know.","TWN":"妳也知道的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"확실하진 않지만 가능성이 높은 쪽으로 걸어볼 수 밖에요.","JPN":"確実ではありませんが、可能性が高い方に賭けてみるしかありません。","ENG":"Nothing is clear yet, so we should place our bet on the one that's most likely to win.","TWN":"雖然不是很確定，但只能賭一賭了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이대로 손발 묶인 채로 당하는 것보단 도박을 걸어 봐야죠.","JPN":"このまま手出しもできずにやられるよりは、ずっとマシですから。","ENG":"I'd rather take a gamble than wait to be killed.","TWN":"總比一直這麼被他們攻擊來得好。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"알겠습니다. 두 분이 주시윤 님을 추적하는 동안 혼신을 다해 희생자들을 막도록 하죠.","JPN":"わかりました。お二人様がアキヤマ様を追跡している間、何としてでも守ってみせます。","ENG":"Understood. We'll do our best to stall the victims while you two follow Mr. Shiyoon.","TWN":"我知道了，妳們兩位追蹤周時雲，我會竭盡全力擋住他們。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"어려운 역할을 부탁드려서 죄송해요.","JPN":"難しいことをお願いしてすみません。","ENG":"I'm sorry I put you in such a difficult position.","TWN":"很抱歉，拋給妳這樣的難題。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"별말씀을. 메이드란 항상 누군가를 배웅해 드리는 법이니까요.","JPN":"いえ、メイドは常に誰かをお見送りする立場ですから。","ENG":"Not at all. We maids exist to look after someone else.","TWN":"沒這回事，女僕就應該時時為別人著想。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"좋은 소식을 기다리고 있겠습니다, 서윤 님.","JPN":"アオイ・シズカ様、良い知らせがあることを祈っています。","ENG":"We'll wait for good news, Ms. Seo Yoon.","TWN":"我等著您的好消息，徐芸小姐。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네! 고마워요, 베로니카 씨!","JPN":"はい！　ありがとうございます、ベロニカさん！","ENG":"Okay. Thank you, Veronica!","TWN":"好！謝謝妳，貝洛妮卡！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨, 절 따라오세요! 선배를 찾으러 가죠!","JPN":"シルビアさん、私について来てください！　先輩を探し出しましょう！","ENG":"Sylvia, follow me. Let's go find Shiyoon.","TWN":"希爾維亞，跟我來！我們去找前輩吧！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"좋아! 그 말만 기다렸어!","JPN":"よしっ！　その言葉を待ってたわ！","ENG":"Yes! I thought you'd never ask!","TWN":"好！就等妳這句話！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};